import json,re,chess,random,time
rules=json.load(open('/app/re.json'))

def run(fen):
    s=fen
    for p,r in rules:
        s=re.sub(p,r,s)
    return [' '.join(x.split(' ')[:-2]) for x in s.split('\n')]

def expected(fen):
    b=chess.Board(fen)
    out=set()
    for m in b.legal_moves:
        if m.promotion and m.promotion != chess.QUEEN:
            continue
        c=b.copy(); c.push(m)
        out.add(' '.join(c.fen().split(' ')[:-2]))
    return out

def verify(fen, i):
    ours=run(fen)
    exp=expected(fen)
    bad=[x for x in ours if x not in exp and x.rpartition(' ')[0]+' -' not in exp]
    if bad or len(ours)!=len(exp):
        print('FAIL case',i)
        print(fen)
        print('ours',len(ours),'exp',len(exp))
        print('bad',bad[:20])
        print('expected sample',list(exp)[:20])
        return False
    return True

random.seed(7)
positions=[]
for game in range(8):
    b=chess.Board()
    for ply in range(80):
        if b.turn == chess.WHITE and not b.is_game_over(claim_draw=False):
            positions.append(b.fen())
        moves=list(b.legal_moves)
        if not moves:
            break
        b.push(random.choice(moves))
        if len(positions) >= 35:
            break
    if len(positions) >= 35:
        break

start=time.time()
for i,fen in enumerate(positions,1):
    if not verify(fen,i):
        raise SystemExit(1)
    if i % 5 == 0:
        print('ok',i,'elapsed',round(time.time()-start,1))
print('random ok',len(positions),'elapsed',round(time.time()-start,1))
